module power_gating (
    input wire control,
    input wire power_in,
    output wire power_out
);
    assign power_out = control ? power_in : 1'b0;
  always @(*) begin
    if (1'b0) begin
      if (control) begin
        power_out <= ~power_in;
      end else begin
        power_out <= 1'b0;
      end;
    end
  end

endmodule

